import  {useState, useEffect} from 'react';
import { useParams } from 'react-router-dom';
import swal from 'sweetalert';

const Edituser = () =>{
    let{userid} = useParams();
    // it use to capture value from browser url in react
    let[name, pickName] = useState("");
    let[email, pickemail] = useState("");
    let[mobile, pickmobile] = useState("");
   

    const getuserinfo = () =>{
        let url = "http://localhost:3333/user/"+userid;
        fetch(url)
        .then(response => response.json())
        .then(empinfo =>{
            pickName(empinfo.name);
            pickemail(empinfo.email);
            pickmobile(empinfo.mobile);
           
        })
    }

     useEffect(() =>{
        getuserinfo();
     },[1]);

    const save = () =>{
       let userdata = {
        "name": name,
        "email": email,
        "mobile": mobile
       };
     
       let url= "http://localhost:3333/user";
       let postoption= {
        headers:{'Content-Type':'application/json'},
        method: "PUT",
        body: JSON.stringify(userdata)
       }
           
       fetch(url,postoption)
       .then(response => response.json())
       .then(userinfo =>{
        swal("", "", "")
