        window.location.href = "#/userlist";
       })
    }

   return(
     <div className="container mt-4">
        <div className="row">
            <div className="col-lg-4"> </div>
            <div className="col-lg-4"> 
              <h1 className="text-center text-primary"> Edit Employeee Details </h1>

                    <div className= "mb-4">
                        <label> Employee Name </label>  
                        <input type="text" className="form-control" onChange={obj => pickName(obj.target.value)} value={name}/>  
                    </div>

                    <div className= "mb-4">
                        <label> Employee Salary </label>  
                        <input type="email" className="form-control" onChange={obj=> pickemail(obj.target.value)} value={email}/>  
                    </div>

                    <div className= "mb-4">
                        <label> Employee Department </label>  
                        <input type="text" className="form-control" onChange={obj=> pickmobile(obj.target.value)} value={mobile} />  
                    </div>

                    <div className="text-center">
                    <button className="btn btn-danger" onClick={save}> update employee </button>
                    </div>
             </div> 

             <div className="col-lg-4"> </div>
             </div> 
        </div>  
   )
}


export default Edituser;
